class InMemoryLedger:
    def __init__(self) -> None:
        self._balances: Dict[str, Decimal] = {}
        self._lock = threading.Lock()

    def apply_debit(self, account_id: str, amount: Decimal) -> Decimal:
        with self._lock:
            current = self._balances.get(account_id, Decimal("0"))
            updated = current - amount
            self._balances[account_id] = updated
            logger.info(
                "Debited account=%s amount=%s new_balance=%s",
                account_id,
                str(amount),
                str(updated),
            )
            return updated

    def apply_credit(self, account_id: str, amount: Decimal) -> Decimal:
        with self._lock:
            current = self._balances.get(account_id, Decimal("0"))
            updated = current + amount
            self._balances[account_id] = updated
            logger.info(
                "Credited account=%s amount=%s new_balance=%s",
                account_id,
                str(amount),
                str(updated),
            )
            return updated

    def get_balance(self, account_id: str) -> Decimal:
        with self._lock:
            return self._balances.get(account_id, Decimal("0"))


