class DynamicMessageHandlerRegistry:
    def __init__(self) -> None:
        self._handlers: Dict[str, Callable[[Any, Dict[str, Any]], None]] = {}

    def register(self, event_type: str, handler: Callable[[Any, Dict[str, Any]], None]) -> None:
        self._handlers[event_type] = handler

    def get(self, event_type: str) -> Callable[[Any, Dict[str, Any]], None]:
        handler = self._handlers.get(event_type)
        if not handler:
            raise HandlerNotFoundError(f"No handler registered for event_type={event_type}")
        return handler

    def register_service_handlers(self, service: Any) -> None:
        for attr_name in dir(service):
            if not attr_name.startswith("handle_"):
                continue
            method = getattr(service, attr_name)
            if not callable(method):
                continue
            event_type = attr_name.removeprefix("handle_")
            self.register(event_type, method)


